import { ISettingPayload, ITheme } from "../interfaces/ISetting";
import { WidgetPos_Bottom, WidgetPos_Left, WidgetPos_Right } from "../constants/WidgetPos";
import { getThemeFromCache, saveThemeToCache, getAccessToken } from './../constants/DefaultSetting';
import {
    UPDATE_WIDGET, 
    UPDATE_MAX_WIDGET, 
    UPDATE_ACTIVE_PANEL,
    UPDATE_SITE_INFO,
    UPDATE_TOOLBARS,
    UPDATE_MAIN_DOCK_PANEL_STYLE,
    UPDATE_LANGUAGE
} from "../constants/actions/settingActionTypes";
import { deepClone } from "../utils/deepClone";
import { signIn } from './githubActions';

const zanejs = (window as any).zanejs;

export const changeLang = (lang: string) => {
    return (dispatch: Function, getState: Function) => {
        dispatch({
            type: UPDATE_LANGUAGE,
            payload: {
                lang
            }
        });
    }
};

/**
 * 获取站点配置信息
 */
export const getSiteData = () => {
    return (dispatch: Function, getState: Function) => {
        fetch(`${process.env.PUBLIC_URL}/assets/config/site.json?r=${zanejs.utils.randomCharacters(10)}`)
            .then(response => {
                response.json().then(result => {
                    let siteInfo: any = {...result}
                    let theme = getThemeFromCache();
                    if (theme) {
                        siteInfo.theme = theme;
                    }
                    
                    const style = {
                        "-moz-filter": `blur(${siteInfo.theme.blur}px)`,
                        "-ms-filter": `blur(${siteInfo.theme.blur}px)`,
                        "-o-filter": `blur(${siteInfo.theme.blur}px)`,
                        "filter": `blur(${siteInfo.theme.blur}px)`,
                        "opacity": siteInfo.theme.opacity,
                        "background-image": `url(${siteInfo.theme.backgroundImage})`,
                        "background-position": "center top",
                        "background-size": "cover",
                        "background-color": `${siteInfo.theme.backgroundColor}`,
                        "background-blend-mode": `${siteInfo.theme.backgroundBlendMode}`
                    };
                    
                    dispatch({
                        type: UPDATE_MAIN_DOCK_PANEL_STYLE,
                        payload: {
                            mainDockPanelStyle: style
                        }
                    });
                    if (siteInfo.langPacks && siteInfo.langPacks.length > 0) {
                        siteInfo.i18n = {};
                        const loop = async () => {
                            let langPack = siteInfo.langPacks.shift();
                            if (langPack) {
                                let response = await fetch(langPack.path);
                                if (response.ok) {
                                    let json = await response.json();
                                    siteInfo.i18n[langPack.lang] = json;
                                }
                                loop();
                            } else {
                                delete siteInfo.langPacks;
                                dispatch({
                                    type: UPDATE_SITE_INFO,
                                    payload: {
                                        siteInfo
                                    }
                                });

                                const token: string|null = getAccessToken();
                                if (token) {
                                    dispatch(signIn(token));
                                }
                            }
                        }
                        loop();
                    } else {
                        dispatch({
                            type: UPDATE_SITE_INFO,
                            payload: {
                                siteInfo
                            }
                        });

                        const token: string|null = getAccessToken();
                        if (token) {
                            dispatch(signIn(token));
                        }
                    }
                });
            });
    }
};

/**
 * 获取工具栏数据
 */
export const getToolbarData = () => {
    return (dispatch: Function, getState: Function) => {
        fetch(`${process.env.PUBLIC_URL}/assets/config/toolbar.json?r=${zanejs.utils.randomCharacters(10)}`)
        .then(response => {
            response.json().then(result => {
                dispatch({
                    type: UPDATE_TOOLBARS,
                    payload: {
                        toolbars: result
                    }
                });
            });
        })
    }
};

/**
 * 更新小部件框架
 * @param widget 更新
 * @param pos 
 */
export const updateWidget = (widget: string|null, pos: number) => {
    return (dispatch: Function, getState: Function) => {
        let state = getState();
        let payload: ISettingPayload = {};
        if (pos === WidgetPos_Left) {
            if (widget == null || state.setting.leftWidget === widget) {
                payload.leftWidget = null;
            } else {
                payload.leftWidget = widget;
            }
        } else if (pos === WidgetPos_Right) {
            if (widget == null || state.setting.rightWidget === widget) {
                payload.rightWidget = null;
            } else {
                payload.rightWidget = widget;
            }
        } else if (pos === WidgetPos_Bottom) {
            if (widget == null || state.setting.bottomWidget === widget) {
                payload.bottomWidget = null;
            } else {
                payload.bottomWidget = widget;
            }
        }
        dispatch({
            type: UPDATE_WIDGET,
            payload
        });
    }
};

export const updateMaxWidget = (widgetPos: number) => {
    return (dispatch: Function, getState: Function) => {
        dispatch({
            type: UPDATE_MAX_WIDGET,
            payload: {
                maxWidget: widgetPos
            }
        });
    }
};

export const updateActivePanel = (panel: string|null|undefined) => {
    return (dispatch: Function, getState: Function) => {
        dispatch({
            type: UPDATE_ACTIVE_PANEL,
            payload: {
                activePanel: panel
            }
        });
    }
};

export const updateTheme = (theme: ITheme) => {
    return (dispatch: Function, getState: Function) => {
        const state = getState();

        saveThemeToCache(theme);

        const siteInfo = deepClone(state.setting.siteInfo);
        siteInfo.theme = {...siteInfo.theme, ...theme};
        dispatch({
            type: UPDATE_SITE_INFO,
            payload: {
                siteInfo
            }
        });

        const style = {
            "-moz-filter": `blur(${theme.blur}px)`,
            "-ms-filter": `blur(${theme.blur}px)`,
            "-o-filter": `blur(${theme.blur}px)`,
            "filter": `blur(${theme.blur}px)`,
            "opacity": theme.opacity,
            "background-image": `url(${theme.backgroundImage})`,
            "background-position": "center top",
            "background-size": "cover",
            "background-color": `${theme.backgroundColor}`,
            "background-blend-mode": `${theme.backgroundBlendMode}`
        };
        dispatch({
            type: UPDATE_MAIN_DOCK_PANEL_STYLE,
            payload: {
                mainDockPanelStyle: style
            }
        });
    }
};