import { LocalStorageUtil } from "../utils/LocalStorageUtil";
import { ITheme } from "../interfaces/ISetting";

const cacheKey: string = 'main_dock_panel_style_cache_key';
const accessTokenCache: string = 'access_token_cache_key';

export const getThemeFromCache = () => {
    const themeCache = LocalStorageUtil.getItem(cacheKey);
    let theme: ITheme|null = null;
    if (themeCache) {
        const _theme = JSON.parse(themeCache);
        if (_theme) {
            theme = _theme;
        }
    }
    if (!theme) {
        theme = {
            blur: 20,
            opacity: 0.2,
            backgroundImage: '/assets/img/bg.jpg',
            backgroundColor: 'rgba(123, 123, 123, 0.35)',
            backgroundBlendMode: 'hue'
        };
    }
    return theme;
};


export const saveThemeToCache = (theme: ITheme) => {
    LocalStorageUtil.setItem(cacheKey, JSON.stringify(theme));
};

export const generateMainDockPanelStyle = (theme: ITheme) => {
    return {
        "-moz-filter": `blur(${theme.blur}px)`,
        "-ms-filter": `blur(${theme.blur}px)`,
        "-o-filter": `blur(${theme.blur}px)`,
        "filter": `blur(${theme.blur}px)`,
        "opacity": theme.opacity,
        "background-image": `url(${theme.backgroundImage})`,
        "background-position": "center top",
        "background-size": "cover",
        "background-color": `${theme.backgroundColor}`,
        "background-blend-mode": `${theme.backgroundBlendMode}`
    };
};

export const getAccessToken = () => {
    return LocalStorageUtil.getItem(accessTokenCache);
}

export const saveAccessToken = (token: string) => {
    if (token) {
        LocalStorageUtil.setItem(accessTokenCache, token);
    } else {
        LocalStorageUtil.removeItem(accessTokenCache);
    }
}

export const DEFAULT_LEFT_WIDGET_WIDTH: number = 300;
export const DEFAULT_RIGHT_WIDGET_HEIGHT: number = 300;
export const DEFAULT_BOTTOM_WIDGET_HEIGHT: number = 260;
export const DEFAULT_ACTIVE_PANEL_COLOR: string = 'rgba(0, 137, 255, 0.05)';
