import { Action, handleActions } from "redux-actions";
import { IBlog, IBlogPayload } from "../interfaces/IBlog";
import { 
    UPDATE_BLOG_NAV_TREE_CONFIG, 
    UPDATE_BLOG_CONFIG_SHA
} from "../constants/actions/blogActionTypes";

const iniState: IBlog = {
    navTreeData: [],
    navSelectedKey: '',
    navExpandedKeys: [],
    navAutoExpandParent: true,
    navEditNodeTitle: '',
    addNavTreeNodeType: '',
    searchValue: '',
    sha: null,
};


export const blogReducer = handleActions<IBlog, IBlogPayload> ({

    [UPDATE_BLOG_NAV_TREE_CONFIG] : (state: IBlog, action: Action<IBlogPayload>): IBlog => {
        return {
            ...state,
            navTreeData: action.payload.navTreeData == undefined ? state.navTreeData : action.payload.navTreeData,
            navSelectedKey: action.payload.navSelectedKey == undefined ? state.navSelectedKey : action.payload.navSelectedKey,
            navExpandedKeys: action.payload.navExpandedKeys == undefined ? state.navExpandedKeys : action.payload.navExpandedKeys,
            navAutoExpandParent: action.payload.navAutoExpandParent == undefined ? state.navAutoExpandParent : action.payload.navAutoExpandParent,
            navEditNodeTitle: action.payload.navEditNodeTitle == undefined ? state.navEditNodeTitle : action.payload.navEditNodeTitle,
            addNavTreeNodeType: action.payload.addNavTreeNodeType == undefined ? state.addNavTreeNodeType : action.payload.addNavTreeNodeType,
            searchValue: action.payload.searchValue == undefined ? state.searchValue : action.payload.searchValue,
            sha: action.payload.sha == undefined ? state.sha : action.payload.sha
        }
    },

    [UPDATE_BLOG_CONFIG_SHA] : (state: IBlog, action: Action<IBlogPayload>): IBlog => {
        return {
            ...state,
            sha: action.payload.sha || state.sha
        }
    },

}, iniState);