import { Action, handleActions } from "redux-actions";
import { IPane, IPanes, IPanePayload } from "../interfaces/IPane";
import { ADD_PANE, UPDATE_PANE, REMOVE_PANE } from "../constants/actions/editorActionTypes";

const iniState: IPanes = {

};

export const panesReducer = handleActions<IPanes, IPanePayload> ({

        [ADD_PANE]: (state: IPanes, action: Action<IPanePayload>): IPanes => {
            let pane: IPane = action.payload as IPane;
            return {
                ...state,
                [pane.id]: pane
            }
        },
        [UPDATE_PANE]: (state: IPanes, action: Action<IPanePayload>): IPanes => {
            let pane: IPane = action.payload as IPane;
            return {
                ...state,
                [pane.id]: pane
            }
        },
        [REMOVE_PANE]: (state: IPanes, action: Action<IPanePayload>): IPanes => {
            let pane: IPane = action.payload as IPane;
            const newState = {...state};
            delete newState[pane.id];
            return newState;
        },
    },
    iniState
);