import { Action, handleActions } from 'redux-actions';
import { IAccount, IAccountPayload } from "../interfaces/IAccount";
import { UPDATE_USER_INFO, SIGN_IN, SIGN_OUT, UPDATE_REPOS } from "../constants/actions/accountActionTypes";

const iniState: IAccount = {
    signInStatus: 0,
    userInfo: null,
    repos: []
};

export const accountReducer = handleActions<IAccount, IAccountPayload> ({
        
        [`${SIGN_IN}_PENDING`]: (state: IAccount, action: Action<IAccountPayload>): IAccount => {
            return {
                ...state,
                signInStatus: 1
            }
        },
        [`${SIGN_IN}_REJECTED`]: (state: IAccount, action: Action<IAccountPayload>): IAccount => {
            return {
                ...state,
                signInStatus: 2
            }
        },
        [`${SIGN_IN}_FULFILLED`]: (state: IAccount, action: Action<IAccountPayload>): IAccount => {
            return {
                ...state,
                signInStatus: 0
            }
        },
        [UPDATE_USER_INFO] : (state: IAccount, action: Action<IAccountPayload>): IAccount => {
            return {
                ...state,
                userInfo: action.payload.userInfo
            }
        },
        [SIGN_OUT] : (state: IAccount, action: Action<IAccountPayload>): IAccount => {
            return {
                ...state,
                userInfo: null
            }
        },
        [UPDATE_REPOS] : (state: IAccount, action: Action<IAccountPayload>): IAccount => {
            return {
                ...state,
                repos: action.payload.repos || []
            }
        },
    },
    iniState
);