import { IBlogNav } from "../interfaces/IBlog";
import { generateTreeItemData } from "./utils/generateTreeItemData";
import { 
    UPDATE_BLOG_NAV_TREE_CONFIG,
    UPDATE_BLOG_CONFIG_SHA
} from "../constants/actions/blogActionTypes";
import { ISite } from "../interfaces/ISetting";
import { getRepoContents } from "./githubActions";

const zanejs = (window as any).zanejs;

/**
 * 获取博文导航数据
 */
export const getBlogNavData = () => {
    return (dispatch: Function, getState: Function) => {
        let state = getState();
        const siteInfo: ISite = state.setting.siteInfo;
        if (siteInfo) {
            dispatch(getRepoContents(
                siteInfo.repo, 
                'assets/config/blog.json', 
                'master', 
                (res: any) => {
                    if (res) {
                        const win = window as any;
                        const zanejs = win.zanejs;
                        let content: any = JSON.parse(zanejs.utils.utf8_decode(decodeURIComponent(win.atob(res.content))));
                        let navTreeData: any[] = [];
                        content.map((item: IBlogNav, index: number) => {
                            navTreeData.push(generateTreeItemData(item, `key-${index}`));
                        });
                        dispatch(updateBlogNavTreeConfig({navTreeData, sha: res.sha}));
                    }
                },
                (res: any) => {
                    console.log(res);
                }
            ));
        }
    }
};

export const updateBlogNavTreeConfig = (payload: any) => {
    return (dispatch: Function, getState: Function) => {
        dispatch({
            type: UPDATE_BLOG_NAV_TREE_CONFIG,
            payload: { ...payload }
        });
    }
};

export const updateBlogSha = (sha: string) => {
    return (dispatch: Function, getState: Function) => {
        dispatch({
            type: UPDATE_BLOG_CONFIG_SHA,
            payload: { sha }
        });
    }
};
