export const splitPane = (paneId: string, splitType: string) => {
    return (dispatch: Function, getState: Function) => {
        let state = getState();
        let paneMap: IPaneMap = deepClone(state.editor.paneMap);
        let resultPaneMap: {pane: IPaneMap|null, parent: IPaneMap|null}|null = searchPane(paneMap, paneId);
        if (resultPaneMap && resultPaneMap.pane) {
            resultPaneMap.pane.splitType = splitType;

            const pane: IPane = state.panes[resultPaneMap.pane.id];

            const pane1: IPane = generatePane();
            pane1.activeFile = pane.activeFile;
            pane1.openFiles = [...pane.openFiles];
            dispatch(addPane(pane1));

            resultPaneMap.pane.primaryPane = {
                id: pane1.id,
                primaryPane: null,
                secondaryPane: null,
                splitType: ''
            };
            
            const pane2 = generatePane();
            pane2.activeFile = pane.activeFile;
            if (pane.activeFile) {
                pane2.openFiles = [pane.activeFile];
                const openfile = state.openfiles[pane.activeFile];
                if (openfile) {
                    if (openfile.openNum == undefined) {
                        openfile.openNum = 2;
                    } else {
                        openfile.openNum++; 
                    }
                    dispatch({
                        type: UPDATE_OPENFILE,
                        payload: {...openfile}
                    });
                }
            } else {
                pane2.openFiles = [];
            }
            dispatch(addPane(pane2));
            dispatch(updateActivePane(pane2.id));

            resultPaneMap.pane.secondaryPane = {
                id: pane2.id,
                primaryPane: null,
                secondaryPane: null,
                splitType: ''
            };

            pane.activeFile = null;
            pane.openFiles = [];
            dispatch(updatePane(pane));
        }

        dispatch({
            type: UPDATE_PANE_MAP,
            payload: {
                paneMap
            }
        });
    }
};

