export const openFile = (file: IOpenFile, $paneId: string|null = null) => {
    return (dispatch: Function, getState: Function) => {
        let state = getState();
        let paneId = $paneId || state.editor.activePane;
        let paneMap: IPaneMap = deepClone(state.editor.paneMap);
        let resultPaneMap: {pane: IPaneMap|null, parent: IPaneMap|null}|null = searchPane(paneMap, paneId);
        if (resultPaneMap && resultPaneMap.pane) {

            file.progress = {percentage: 0};
            dispatch({
                type: ADD_OPENFILE,
                payload: {...file}
            });

            const pane: IPane = state.panes[resultPaneMap.pane.id];
            pane.activeFile = file.path;
            let isHave = false;
            pane.openFiles.map(path => {
                if (path == file.path) {
                    isHave = true;
                }
            });
            if (!isHave) {
                pane.openFiles.push(file.path);
            }
            dispatch(updatePane(pane));
            if (zanejs.utils.isAbsoluteUrl(file.path)) {
                dispatch(updateActiveFileContent(file));
            } else {
                const win = window as any;
                const zanejs = win.zanejs;
                const siteInfo: ISite = state.setting.siteInfo;
                if (siteInfo) {
                    dispatch(getRepoContents(
                        siteInfo.repo, 
                        file.path, 
                        'master', 
                        (res: any) => {
                            if (res) {
                                file.content = zanejs.utils.utf8_decode(win.atob(res.content));
                                file.sha = res.sha;
                                dispatch(updateFile(file));
                            }
                        }
                    ));
                }
            }
        }
    }
};

export const closeFile = (file: IOpenFile, $paneId: string|null = null) => {
    return (dispatch: any, getState: any) => {
        let state = getState();
        let paneId: string = $paneId || state.editor.activePane;
        let paneMap: IPaneMap = deepClone(state.editor.paneMap);
        let resultPaneMap: {pane: IPaneMap|null, parent: IPaneMap|null}|null = searchPane(paneMap, paneId);
        if (resultPaneMap && resultPaneMap.pane) {

            dispatch({
                type: REMOVE_OPENFILE,
                payload: {...file}
            });

            const pane: IPane = state.panes[resultPaneMap.pane.id];
            pane.openFiles.map((path, index) => {
                if (path == file.path) {
                    pane.openFiles.splice(index, 1);
                }
            });
            if (pane.openFiles.length > 0) {
                pane.activeFile = pane.openFiles[pane.openFiles.length - 1];
            } else {
                pane.activeFile = null;
            }
            dispatch(updatePane(pane));
        }
    };
};

