export const updateActiveFileContent = (file: IOpenFile) => {
    
    return (dispatch: Function, getState: Function) => {
        if (file.content == undefined) {
            fetch(`${file.path}?r=${zanejs.utils.randomCharacters(10)}`)
                .then((r) => {
                    if (r.status == 200) {
                        
                    } else {
                        file.content = `## ${formatMessage({id: "app.page404Title"})}!!!`;
                        file.err = formatMessage({id: "app.page404Title"});
                        dispatch(updateFile(file));
                    }
                    return r;
                })
                .then(
                    fetchProgress({
                        onProgress(progress: number) {
                            file.progress = progress;
                            dispatch(updateFile(file));
                        },
                        onError(err: any) {
                            file.err = err;
                            dispatch(updateFile(file));
                        },
                    }))
                .then(r => r.text())
                .then((content) => {
                    if (file.content == undefined) {
                        file.content = content;
                    }
                    dispatch(updateFile(file));
                })
                .catch((err) => {
                    console.log(err);
                });
        }
    }
};