import { Action, handleActions } from "redux-actions";
import { ADD_OPENFILE, UPDATE_OPENFILE, REMOVE_OPENFILE } from "../constants/actions/editorActionTypes";
import { IOpenFiles, IOpenFile, IOpenFilePayload } from "../interfaces/IOpenfile";

const iniState: IOpenFiles = {

};

export const openfilesReducer = handleActions<IOpenFiles, IOpenFilePayload> ({

        [ADD_OPENFILE]: (state: IOpenFiles, action: Action<IOpenFilePayload>): IOpenFiles => {
            let openfile: IOpenFile = action.payload as IOpenFile;
            if (state[openfile.path]) {
                openfile = {...state[openfile.path]}; 
                if (openfile.openNum == undefined) {
                    openfile.openNum = 2;
                } else {
                    openfile.openNum++;
                }
            }
            return {
                ...state,
                [openfile.path]: openfile
            }
        },
        [UPDATE_OPENFILE]: (state: IOpenFiles, action: Action<IOpenFilePayload>): IOpenFiles => {
            let openfile: IOpenFile = action.payload as IOpenFile;
            return {
                ...state,
                [openfile.path]: openfile
            }
        },
        [REMOVE_OPENFILE]: (state: IOpenFiles, action: Action<IOpenFilePayload>): IOpenFiles => {
            const newState = {...state};
            let openfile: IOpenFile = newState[action.payload.path]
            if (openfile) {
                if (openfile.openNum == undefined) {
                    delete newState[openfile.path];
                } else {
                    openfile.openNum--;
                    if (openfile.openNum == 0) {
                        delete newState[openfile.path];
                    }
                }
            }
            
            return newState;
        }
    },
    iniState
);